// Bootstraps the Swift/WASM runtime ONCE per app launch. The bundle is generated by BridgeJS from
// DemoCore.ViewModel's `// SKIP @bridge` marker. Loaded as a /public module via a
// <script type="module"> tag so the browser imports it (and /swift/index.js) natively, rather than
// routing them through Vite's source transforms.
//
// Exposes `window.swiftReady`: a Promise resolving to the bridge's exports once the runtime is up.
// Bootstrap happens here, once; callers then create as many objects as they need, e.g.
//   const swift = await window.swiftReady
//   const vm = await swift.createViewModelBridge()
import { init } from "/swift/index.js"

window.swiftReady = (async () => {
    const { exports } = await init()   // instantiate the wasm module
    exports.bootstrapSwiftRuntime()    // install Swift's concurrency runtime — ONCE
    return exports
})()
